# effect_size.py — compute Cohen's d for continuous metrics, relative effect for rates

def cohens_d(prod_values, cand_values):
    """Standardized effect size for continuous distributions."""
    import statistics
    prod_mean = statistics.mean(prod_values)
    cand_mean = statistics.mean(cand_values)
    # Pooled standard deviation
    n1, n2 = len(prod_values), len(cand_values)
    s1, s2 = statistics.stdev(prod_values), statistics.stdev(cand_values)
    pooled_sd = ((( n1 - 1) * s1**2 + (n2 - 1) * s2**2) / (n1 + n2 - 2)) ** 0.5
    if pooled_sd == 0:
        return 0.0
    return (cand_mean - prod_mean) / pooled_sd

def relative_effect(prod_mean, cand_mean):
    """Percentage change for rate metrics."""
    if prod_mean == 0:
        return float("inf") if cand_mean > 0 else 0.0
    return (cand_mean - prod_mean) / prod_mean

def classify_latency_effect(prod_p99_values, cand_p99_values):
    d = cohens_d(prod_p99_values, cand_p99_values)
    rel = relative_effect(
        sum(prod_p99_values) / len(prod_p99_values),
        sum(cand_p99_values) / len(cand_p99_values)
    )
    if rel > 0.25:
        return "P0_BLOCK", f"p99 latency {rel*100:.1f}% higher (exceeds 25% P0 threshold)"
    elif rel > 0.10:
        return "P1_CONDITIONAL", f"p99 latency {rel*100:.1f}% higher (10–25% P1 range)"
    else:
        return "PASS", f"p99 latency {rel*100:.1f}% change (within 10% tolerance)"
